// Simple Supabase client (no SDK needed)
const sb = {
  from: (table) => ({
    select: async (cols = "*", order = null) => {
      const orderParam = order ? `&order=${order}` : "";
      const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?select=${cols}${orderParam}`, {
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` }
      });
      return res.json();
    },
    insert: async (data) => {
      const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
        method: "POST",
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json", Prefer: "return=representation" },
        body: JSON.stringify(data)
      });
      return res.json();
    },
    update: async (data, match) => {
      const params = Object.entries(match).map(([k,v]) => `${k}=eq.${v}`).join("&");
      const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?${params}`, {
        method: "PATCH",
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json", Prefer: "return=representation" },
        body: JSON.stringify(data)
      });
      return res.json();
    },
    delete: async (match) => {
      const params = Object.entries(match).map(([k,v]) => `${k}=eq.${v}`).join("&");
      const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?${params}`, {
        method: "DELETE",
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` }
      });
      return res.ok;
    }
  }),
  storageDelete: async (path) => {
    const res = await fetch(`${SUPABASE_URL}/storage/v1/object/fotos/${path}`, {
      method: "DELETE",
      headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` }
    });
    return res.ok;
  },
  storage: {
    upload: async (path, file) => {
      const res = await fetch(`${SUPABASE_URL}/storage/v1/object/fotos/${path}`, {
        method: "POST",
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": file.type },
        body: file
      });
      const data = await res.json();
      return { url: `${SUPABASE_URL}/storage/v1/object/public/fotos/${path}`, error: data.error };
    }
  }
};

