function PinScreen({ onUnlock }) {
  const [input, setInput] = useState("");
  const [error, setError] = useState(false);
  const [shake, setShake] = useState(false);
  const handleKey = (k) => {
    if (k === "⌫") { setInput(p => p.slice(0,-1)); setError(false); return; }
    if (input.length >= PINCODE.length) return;
    const next = input + k;
    setInput(next);
    if (next.length === PINCODE.length) {
      if (next === PINCODE) { setTimeout(() => onUnlock(), 200); }
      else { setShake(true); setError(true); setTimeout(() => { setInput(""); setShake(false); setError(false); }, 700); }
    }
  };
  return (
    <div className="pin-screen">
      <div className="pin-deco"><span /><span /></div>
      <div className="pin-inner">
        <div className="pin-badge">🌵</div>
        <div className="pin-title">Hasta la Boda</div>
        <div className="pin-sub">De reis naar de bruiloft van Roel</div>
        <div className="pin-label">Voer de code in</div>
        <div className="pin-boxes">
          {Array.from({ length: PINCODE.length }).map((_, i) => (
            <div key={i} className={`pin-box ${i < input.length ? "filled" : ""} ${shake && i < input.length ? "error" : ""}`}>
              {i < input.length ? input[i] : ""}
            </div>
          ))}
        </div>
        <div className="pin-keyboard">
          {PIN_KEYS.map((k, i) => (
            <div key={i} className="pin-key" onClick={() => k && handleKey(k)} style={{ opacity: k ? 1 : 0, pointerEvents: k ? "auto" : "none" }}>{k}</div>
          ))}
        </div>
        <div className="pin-error-msg">{error ? "Onjuiste code, probeer opnieuw" : ""}</div>
      </div>
    </div>
  );
}

